/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const N = nums.length;

    // 1. Build Adjacency List
    const adj = Array(N).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let totalCount = 0;

    // Iterate through all non-empty subsets (masks 1 to 2^N - 1)
    const numSubsets = 1 << N;

    for (let mask = 1; mask < numSubsets; mask++) {
        let sumParity = 0;
        let nodeCount = 0;
        let startNode = -1;

        // Calculate sum parity, count nodes, and find a starting node
        for (let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                nodeCount++;
                sumParity = (sumParity + nums[i]) % 2;
                if (startNode === -1) {
                    startNode = i;
                }
            }
        }

        // Check condition 2: Sum of values must be even
        if (sumParity !== 0) {
            continue;
        }

        // Check condition 1: Induced subgraph must be connected

        // For a single node subset, it is always connected
        if (nodeCount === 1) {
            totalCount++;
            continue;
        }

        // BFS for connectivity check
        const queue = [startNode];
        const visited = new Set([startNode]);
        let reachableCount = 1;

        let head = 0;
        while (head < queue.length) {
            const u = queue[head++];

            for (const v of adj[u]) {
                // Check if v is in the subset (mask) AND v has not been visited
                if (((mask >> v) & 1) && !visited.has(v)) {
                    visited.add(v);
                    queue.push(v);
                    reachableCount++;
                }
            }
        }

        // If all nodes in the subset were reached, the subgraph is connected
        if (reachableCount === nodeCount) {
            totalCount++;
        }
    }

    return totalCount;
}

