        // BFS for connectivity check

        // Queue implementation using a mutable list acting as a queue (FIFO)
        var queue: List[Int] = List(startNode)

        // Visited array/set. Since N <= 13, a simple boolean array is fast.
        val visited = Array.fill(N)(false)
        visited(startNode) = true

        var reachableCount: Int = 1

        var head = 0
        while (head < queue.size) {
            val u = queue(head)
