            // Iterate over neighbors of u in the original graph
            for (v <- adj(u)) {
                // Check if v is in the subset (mask) AND v has not been visited
                if (((mask >> v) & 1 == 1) && !visited(v)) {
                    visited(v) = true
                    // Add to queue (appending to the list simulates queue growth)
                    queue = queue :+ v 
                    reachableCount += 1
                }
            }
        }

